-- 2282_hyrox_programs.sql
-- Phase 3 (HYROX): seed two HYROX programs into the unified `programs` catalog so they
-- flow through the existing browse→preview→import→schedule pipeline (no new engine).
-- Full Simulation = the 8-station race; Race Prep = an 8-week build (32 workouts).
-- Applied to prod via Supabase REST on 2026-06-24; idempotent INSERT…WHERE NOT EXISTS for repo parity.

INSERT INTO programs (program_name, program_category, program_subcategory, difficulty_level, duration_weeks, sessions_per_week, session_duration_minutes, goals, description, short_description, workouts, has_workouts, featured_rank)
SELECT 'HYROX Full Simulation','Sport Training','HYROX','Advanced',1,1,70,ARRAY['Endurance','Athletic Performance','Conditioning']::text[],'The full HYROX race simulation: 8×1 km runs interleaved with the 8 functional stations in official order (SkiErg, Sled Push, Sled Pull, Burpee Broad Jumps, Row, Farmers Carry, Sandbag Lunges, Wall Balls). Use it as a benchmark before race day.','The full 8-station HYROX race simulation.','{"program": "HYROX Full Simulation", "category": "Sport Training", "difficulty": "Advanced", "duration": "1 week", "session_duration": 70, "sessions_per_week": 1, "goals": ["Endurance", "Athletic Performance", "Conditioning"], "description": "The full HYROX race simulation: 8\u00d71 km runs interleaved with the 8 functional stations in official order (SkiErg, Sled Push, Sled Pull, Burpee Broad Jumps, Row, Farmers Carry, Sandbag Lunges, Wall Balls). Use it as a benchmark before race day.", "workouts": [{"day": 1, "type": "HYROX / Conditioning", "workout_name": "HYROX Full Simulation", "exercises": [{"exercise_name": "Dynamic warm-up", "sets": 1, "reps": "8 minutes", "rest_seconds": 0, "notes": "Easy jog + leg swings + 10 air squats"}, {"exercise_name": "1 km Run", "sets": 1, "reps": "1 km", "rest_seconds": 0, "notes": "Race pace \u2014 these runs are 50% of HYROX"}, {"exercise_name": "SkiErg", "sets": 1, "reps": "1000 m", "rest_seconds": 90}, {"exercise_name": "1 km Run", "sets": 1, "reps": "1 km", "rest_seconds": 0, "notes": "Race pace \u2014 these runs are 50% of HYROX"}, {"exercise_name": "Sled Push", "sets": 1, "reps": "50 m", "rest_seconds": 90}, {"exercise_name": "1 km Run", "sets": 1, "reps": "1 km", "rest_seconds": 0, "notes": "Race pace \u2014 these runs are 50% of HYROX"}, {"exercise_name": "Sled Pull", "sets": 1, "reps": "50 m", "rest_seconds": 90}, {"exercise_name": "1 km Run", "sets": 1, "reps": "1 km", "rest_seconds": 0, "notes": "Race pace \u2014 these runs are 50% of HYROX"}, {"exercise_name": "Burpee Broad Jumps", "sets": 1, "reps": "80 m", "rest_seconds": 90}, {"exercise_name": "1 km Run", "sets": 1, "reps": "1 km", "rest_seconds": 0, "notes": "Race pace \u2014 these runs are 50% of HYROX"}, {"exercise_name": "Rowing", "sets": 1, "reps": "1000 m", "rest_seconds": 90}, {"exercise_name": "1 km Run", "sets": 1, "reps": "1 km", "rest_seconds": 0, "notes": "Race pace \u2014 these runs are 50% of HYROX"}, {"exercise_name": "Farmers Carry", "sets": 1, "reps": "200 m", "rest_seconds": 90}, {"exercise_name": "1 km Run", "sets": 1, "reps": "1 km", "rest_seconds": 0, "notes": "Race pace \u2014 these runs are 50% of HYROX"}, {"exercise_name": "Sandbag Lunges", "sets": 1, "reps": "100 m", "rest_seconds": 90}, {"exercise_name": "1 km Run", "sets": 1, "reps": "1 km", "rest_seconds": 0, "notes": "Race pace \u2014 these runs are 50% of HYROX"}, {"exercise_name": "Wall Balls", "sets": 1, "reps": "100 reps", "rest_seconds": 0}, {"exercise_name": "Cool-down walk + stretch", "sets": 1, "reps": "8 minutes", "rest_seconds": 0}]}]}'::jsonb,true,7
WHERE NOT EXISTS (SELECT 1 FROM programs WHERE program_name='HYROX Full Simulation');

